<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Personal Expense Tracker</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: system-ui, -apple-system, sans-serif; background: #f4f6f9; color: #222; line-height: 1.5; padding: 1rem; max-width: 800px; margin: 0 auto; }
  h1 { font-size: 1.4rem; margin-bottom: 1rem; }
  h2 { font-size: 1.1rem; margin: 1.5rem 0 0.5rem; }

  /* Form */
  .entry-form { background: #fff; padding: 1rem; border-radius: 6px; border: 1px solid #d0d7de; margin-bottom: 1rem; }
  .entry-form label { display: block; font-weight: 600; margin-top: 0.5rem; margin-bottom: 0.2rem; font-size: 0.9rem; }
  .entry-form input, .entry-form select { width: 100%; padding: 0.45rem 0.5rem; border: 1px solid #aaa; border-radius: 4px; font-size: 0.95rem; }
  .entry-form button { margin-top: 0.75rem; padding: 0.5rem 1.2rem; background: #2563eb; color: #fff; border: none; border-radius: 4px; font-size: 0.95rem; cursor: pointer; }
  .entry-form button:hover { background: #1d4ed8; }
  #form-error { color: #b91c1c; min-height: 1.2em; margin-top: 0.5rem; font-size: 0.9rem; }

  /* Filters */
  .filters { background: #fff; padding: 1rem; border-radius: 6px; border: 1px solid #d0d7de; display: flex; gap: 0.75rem; align-items: end; flex-wrap: wrap; margin-bottom: 1rem; }
  .filters > div { display: flex; flex-direction: column; }
  .filters label { font-weight: 600; font-size: 0.85rem; margin-bottom: 0.15rem; }
  .filters select, .filters input { padding: 0.4rem 0.5rem; border: 1px solid #aaa; border-radius: 4px; font-size: 0.9rem; min-width: 130px; }

  /* Summary */
  .summary-bar { background: #fff; padding: 0.75rem 1rem; border-radius: 6px; border: 1px solid #d0d7de; margin-bottom: 1rem; display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; gap: 0.5rem; }
  .summary-bar strong { font-size: 1rem; }
  #total { color: #16a34a; font-weight: 700; font-size: 1.1rem; }
  .cat-totals { display: flex; gap: 1rem; flex-wrap: wrap; }
  .cat-total { background: #f0fdf4; padding: 0.25rem 0.6rem; border-radius: 4px; font-size: 0.85rem; border: 1px solid #bbf7d0; }

  /* Expense list */
  .expense-list { list-style: none; }
  .expense { display: flex; justify-content: space-between; align-items: center; background: #fff; padding: 0.6rem 1rem; border-radius: 4px; margin-bottom: 0.35rem; border: 1px solid #e5e7eb; }
  .expense-info { display: flex; gap: 1rem; align-items: center; flex-wrap: wrap; }
  .expense-amount { font-weight: 700; color: #dc2626; min-width: 80px; }
  .expense-cat { background: #eef2ff; padding: 0.15rem 0.5rem; border-radius: 3px; font-size: 0.85rem; text-transform: capitalize; }
  .expense-date { color: #6b7280; font-size: 0.85rem; }
  .expense-note { color: #9ca3af; font-size: 0.85rem; max-width: 200px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
  .exp-del { background: none; border: 1px solid #f87171; color: #dc2626; padding: 0.2rem 0.55rem; border-radius: 4px; cursor: pointer; font-size: 0.85rem; }
  .exp-del:hover { background: #fef2f2; }

  .empty-msg { text-align: center; color: #9ca3af; padding: 2rem; font-style: italic; }
</style>
</head>
<body>

<h1>💰 Expense Tracker</h1>

<!-- Entry Form -->
<div class="entry-form">
  <label for="amount">Amount ($)</label>
  <input type="number" id="amount" placeholder="e.g. 25.50" step="0.01" min="0">

  <label for="category">Category</label>
  <select id="category">
    <option value="groceries">Groceries</option>
    <option value="transport">Transport</option>
    <option value="bills">Bills</option>
    <option value="fun">Fun</option>
  </select>

  <label for="date">Date</label>
  <input type="date" id="date">

  <label for="note">Note (optional)</label>
  <input type="text" id="note" placeholder="e.g. Weekly shopping">

  <button id="add-expense">Add Expense</button>
  <div id="form-error"></div>
</div>

<!-- Filters -->
<div class="filters">
  <div>
    <label for="filter-category">Category</label>
    <select id="filter-category">
      <option value="all">All</option>
      <option value="groceries">Groceries</option>
      <option value="transport">Transport</option>
      <option value="bills">Bills</option>
      <option value="fun">Fun</option>
    </select>
  </div>
  <div>
    <label for="filter-from">From date</label>
    <input type="date" id="filter-from">
  </div>
  <div>
    <label for="filter-to">To date</label>
    <input type="date" id="filter-to">
  </div>
</div>

<!-- Summary -->
<div class="summary-bar">
  <div>Total: <span id="total">0.00</span></div>
  <div class="cat-totals" id="cat-totals"></div>
</div>

<!-- Expense List -->
<h2>Expenses</h2>
<ul class="expense-list" id="expense-list"></ul>

<script>
(function () {
  const STORAGE_KEY = 'expense_tracker_data';
  const CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];

  // --- State ---
  let expenses = loadExpenses();

  // Set default date to today
  document.getElementById('date').valueAsDate = new Date();

  // --- DOM refs ---
  const amountInput   = document.getElementById('amount');
  const categorySelect = document.getElementById('category');
  const dateInput     = document.getElementById('date');
  const noteInput     = document.getElementById('note');
  const addBtn        = document.getElementById('add-expense');
  const formError     = document.getElementById('form-error');

  const filterCategory = document.getElementById('filter-category');
  const filterFrom     = document.getElementById('filter-from');
  const filterTo       = document.getElementById('filter-to');

  const expenseList   = document.getElementById('expense-list');
  const totalEl       = document.getElementById('total');
  const catTotalsEl   = document.getElementById('cat-totals');

  // --- Persistence ---
  function loadExpenses() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      return raw ? JSON.parse(raw) : [];
    } catch { return []; }
  }

  function saveExpenses() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
  }

  // --- Validation & Add ---
  addBtn.addEventListener('click', function () {
    const rawAmount = amountInput.value.trim();
    const dateVal   = dateInput.value.trim();

    // Clear previous error
    formError.textContent = '';

    if (!rawAmount || isNaN(Number(rawAmount)) || Number(rawAmount) <= 0) {
      formError.textContent = 'Please enter a valid positive amount.';
      return;
    }
    if (!dateVal) {
      formError.textContent = 'Please select a date.';
      return;
    }

    const expense = {
      id: Date.now().toString(36) + Math.random().toString(36).slice(2, 7),
      amount: parseFloat(Number(rawAmount).toFixed(2)),
      category: categorySelect.value,
      date: dateVal,
      note: noteInput.value.trim()
    };

    expenses.unshift(expense); // newest first
    saveExpenses();
    render();

    // Reset amount field only (as specified)
    amountInput.value = '';
  });

  // --- Delete ---
  expenseList.addEventListener('click', function (e) {
    if (!e.target.classList.contains('exp-del')) return;
    const id = e.target.dataset.id;
    expenses = expenses.filter(function (ex) { return ex.id !== id; });
    saveExpenses();
    render();
  });

  // --- Filters ---
  [filterCategory, filterFrom, filterTo].forEach(function (el) {
    el.addEventListener('change', render);
  });

  // --- Render ---
  function getVisible() {
    const catFilter = filterCategory.value;
    const fromDate  = filterFrom.value;
    const toDate    = filterTo.value;

    return expenses.filter(function (ex) {
      if (catFilter !== 'all' && ex.category !== catFilter) return false;
      if (fromDate && ex.date < fromDate) return false;
      if (toDate   && ex.date > toDate)   return false;
      return true;
    });
  }

  function render() {
    const visible = getVisible();

    // --- Expense list ---
    expenseList.innerHTML = '';
    if (visible.length === 0) {
      expenseList.innerHTML = '<li class="empty-msg">No expenses to show.</li>';
    } else {
      visible.forEach(function (ex) {
        const li = document.createElement('li');
        li.className = 'expense';
        li.dataset.id = ex.id;

        const info = document.createElement('div');
        info.className = 'expense-info';

        const amtSpan = document.createElement('span');
        amtSpan.className = 'expense-amount';
        amtSpan.textContent = formatCurrency(ex.amount);

        const catSpan = document.createElement('span');
        catSpan.className = 'expense-cat';
        catSpan.textContent = ex.category;

        const dateSpan = document.createElement('span');
        dateSpan.className = 'expense-date';
        dateSpan.textContent = ex.date;

        info.appendChild(amtSpan);
        info.appendChild(catSpan);
        info.appendChild(dateSpan);

        if (ex.note) {
          const noteSpan = document.createElement('span');
          noteSpan.className = 'expense-note';
          noteSpan.title = ex.note;
          noteSpan.textContent = ex.note;
          info.appendChild(noteSpan);
        }

        const delBtn = document.createElement('button');
        delBtn.className = 'exp-del';
        delBtn.dataset.id = ex.id;
        delBtn.textContent = '✕';
        delBtn.title = 'Delete expense';

        li.appendChild(info);
        li.appendChild(delBtn);
        expenseList.appendChild(li);
      });
    }

    // --- Total ---
    const sum = visible.reduce(function (acc, ex) { return acc + ex.amount; }, 0);
    totalEl.textContent = formatCurrency(sum);

    // --- Per-category totals ---
    catTotalsEl.innerHTML = '';
    CATEGORIES.forEach(function (cat) {
      const catSum = visible.filter(function (ex) { return ex.category === cat; })
                           .reduce(function (acc, ex) { return acc + ex.amount; }, 0);

      const div = document.createElement('div');
      div.className = 'cat-total';
      div.dataset.cat = cat;
      div.textContent = cat.charAt(0).toUpperCase() + cat.slice(1) + ': ' + formatCurrency(catSum);
      catTotalsEl.appendChild(div);
    });
  }

  function formatCurrency(n) {
    return n.toFixed(2);
  }

  // --- Initial render ---
  render();
})();
</script>
</body>
</html>
